codeExample:
pipeline {
    agent any
    tools {
        maven 'Maven 3.8'
        jdk 'Java 11'
    }
    stages {
        stage('Checkout') {
            steps { git 'https://github.com/org/repo.git' }
        }
        stage('Test') {
            steps { sh 'mvn clean test -Dsuite=regression.xml' }
        }
    }
    post {
        always {
            junit 'target/surefire-reports/*.xml'
        }
    }
}
